+#![cfg(test)]
+use crate::command_palette::{CommandPalette, MatchType, scorer::BayesianScorer};
+use ftui_core::event::{Event, KeyCode, KeyEvent, KeyEventKind, Modifiers};
+use proptest::prelude::*;
