+    let scorer = BayesianScorer::new();
+    // Space is a valid char, should match space in title
+    let result = scorer.score(" ", "Hello World");
+    assert_eq!(result.match_type, MatchType::Substring);
+    assert!(!result.match_positions.is_empty());
+}
